form:Form.form:Scripts:
		function LoadForm()
{
  SetPuesto();
  Ctrl('oi_calendario').SetWhere("ORG27_CAL_FERIADOS.oi_calendario IN (SELECT ORG03_FERIADOS_EMP.oi_calendario FROM ORG03_FERIADOS_EMP WHERE ORG03_FERIADOS_EMP.oi_empresa = "+ Ctrl("oi_empresa").GetXValue() + ")");		
	Ctrl('f_ingreso').SetTypedValue(new Date());			

	//PRIMERO IDENTIFICO QUE CASO ESTOY TRATANDO EN LA FIRMA DEL CONTRATO	
	var persona;	
	var np = new NomadProxy("", ut);
	var nSQL = np.SQLService();	
	persona = nSQL.GetOBJ(Ctrl("main").getResource("QRY_PERSONA_REC"), "<PARAM oi_reclutado=\""+Ctrl("oi_reclutado").GetXValue()+"\" />"); 			

	//CASO A. EL CV DEL RECLUTADO NO TIENE ASIGNADO OI_PERSONAL. ES UN POSTULANTE EXTERNO
	if(persona.oi_personal == "0")   
	{
		existePer = nSQL.GetOBJ(Ctrl("main").getResource("QRY_EXISTE_PER"), "<PARAM oi_reclutado=\""+Ctrl("oi_reclutado").GetXValue()+"\" />"); 			
		if(existePer.value == "1")
		{
			CtrlEnabled("SAVE", false);
			alert('Ya existe registrada una persona para el reclutado indicado. Por favor, asocie la misma al CV en la pantalla de Administración de CVs');
		}
		else
		{			
			Ctrl('hid_caso').SetXValue("1"); 		
			SetLegajo();  
			SetSexo();
			CtrlEnabled("e_numero_legajo", true);
		}
	}
	else
	{
		legajoAct = nSQL.GetOBJ(Ctrl("main").getResource("QRY_LEGAJO_ACTIVO"), "<PARAM oi_aviso=\""+Ctrl("oi_aviso").GetXValue()+"\" oi_reclutado=\""+Ctrl("oi_reclutado").GetXValue()+"\" />"); 					
		//CASO B.1. EL CV TIENE CARGADO PERSONAL, LA PERSONA TIENE UN LEGAJO ACTIVO EN LA EMPRESA DEL AVISO
		if(legajoAct.oi_personal_emp != "0")
		{
			Ctrl('hid_caso').SetXValue("2");
			Ctrl('hid_per_emp').SetCValue(legajoAct.oi_personal_emp)			
			Ctrl('e_numero_legajo').SetXValue(legajoAct.e_numero_legajo);			
			Ctrl('oi_tipo_personal').SetXValue(legajoAct.oi_tipo_personal);
			Ctrl('oi_calendario').SetXValue(legajoAct.oi_calendario_ult);
			Ctrl('oi_ctro_costo').SetXValue(legajoAct.oi_ctro_costo_ult);
			Ctrl('o_personal_emp').SetXValue(legajoAct.o_personal_emp);		
			Ctrl('c_sexo').SetXValue(legajoAct.c_sexo);			
			CtrlEnabled("e_numero_legajo", false);			
		}
		else
		{
			//CASO B.2. EL CV TIENE CARGADO PERSONAL, LA PERSONA TIENE UN LEGAJO ACTIVO EN UNA EMPRESA DIFERENTE A LA DEL PUESTO DEL AVISO
			legajoActDif = nSQL.GetOBJ(Ctrl("main").getResource("QRY_LEG_ACTIVO_DIF"), "<PARAM oi_aviso=\""+Ctrl("oi_aviso").GetXValue()+"\" oi_reclutado=\""+Ctrl("oi_reclutado").GetXValue()+"\" />"); 				    
	    if(legajoActDif.oi_personal_emp != "0")
	    {	
	    	Ctrl('hid_caso').SetXValue("3");
				SetLegajo();
				//VER COMO HACER EL EGRESO EN ESTE CASO 
				Ctrl('hid_per_emp').SetCValue(legajoActDif.oi_personal_emp)				
				Ctrl('oi_tipo_personal').SetXValue(legajoActDif.oi_tipo_personal);
				Ctrl('oi_calendario').SetXValue(legajoActDif.oi_calendario_ult);
				Ctrl('oi_ctro_costo').SetXValue(legajoActDif.oi_ctro_costo_ult);
				Ctrl('o_personal_emp').SetXValue(legajoActDif.o_personal_emp);
				Ctrl('c_sexo').SetXValue(legajoActDif.c_sexo);					
				CtrlEnabled("e_numero_legajo", true);				
			}
			else
			{
				//CASO B.3. EL CV TIENE CARGADO PERSONAL, LA PERSONA TIENE UN LEGAJO INACTIVO EN LA EMPRESA DEL PUESTO DEL AVISO 
				legajoInactivo = nSQL.GetOBJ(Ctrl("main").getResource("QRY_LEG_INACTIVO"), "<PARAM oi_aviso=\""+Ctrl("oi_aviso").GetXValue()+"\" oi_reclutado=\""+Ctrl("oi_reclutado").GetXValue()+"\" />"); 				   	 	
	    	if(legajoInactivo.oi_personal_emp != "0")
	    	{	
	    		Ctrl('hid_caso').SetXValue("4");
					//VER COMO HACER EL REINGRESO EN ESTE CASO 
					Ctrl('hid_per_emp').SetCValue(legajoInactivo.oi_personal_emp)
					Ctrl('e_numero_legajo').SetXValue(legajoInactivo.e_numero_legajo);					
					Ctrl('oi_tipo_personal').SetXValue(legajoInactivo.oi_tipo_personal);
					Ctrl('oi_calendario').SetXValue(legajoInactivo.oi_calendario_ult);
					Ctrl('oi_ctro_costo').SetXValue(legajoInactivo.oi_ctro_costo_ult);
					Ctrl('o_personal_emp').SetXValue(legajoInactivo.o_personal_emp);
					Ctrl('c_sexo').SetXValue(legajoInactivo.c_sexo);						
					CtrlEnabled("e_numero_legajo", false);
				}
				else
				{
					//EXISTE LA PERSONA Y EL LEGAJO ESTA INACTIVO EN OTRA EMPRESA. SE TRATA COMO UN CASO 1
					Ctrl('hid_caso').SetXValue("1"); 		
					SetLegajo();
					CtrlEnabled("e_numero_legajo", true);
				}
			}			
	  }
	} 
}

function SetLegajo()
{
	var legajo;				
	var np = new NomadProxy("", ut);
	var nSQL = np.SQLService();

	legajo = nSQL.GetOBJ(Ctrl("main").getResource("QRY_LEGAJO"), "<PARAM oi_aviso=\""+Ctrl("oi_aviso").GetXValue()+"\" />"); 			
	Ctrl("e_numero_legajo").SetXValue(legajo.e_numero_legajo);					
 	CtrlEnabled("e_numero_legajo", false);                         	
}       
function SetSexo()
{
	var legajo;				
	var np = new NomadProxy("", ut);
	var nSQL = np.SQLService();

	cv = nSQL.GetOBJ(Ctrl("main").getResource("QRY_SEXO"), "<PARAM oi_reclutado=\""+Ctrl("oi_reclutado").GetXValue()+"\" />"); 			
	if(cv.c_sexo == 'SE' || cv.c_sexo == '')
	{                                   
		Ctrl("c_sexo").SetXValue(''); 
		CtrlEnabled("c_sexo",true);
	}                           
	else
	{
		Ctrl("c_sexo").SetXValue(cv.c_sexo);					
		CtrlEnabled("c_sexo",false);	
	}

}

function SetPuesto()
{
	var puesto;
	var np = new NomadProxy("", ut);
	var nSQL = np.SQLService();

	puesto = nSQL.GetOBJ(Ctrl("main").getResource("QRY_PUESTO"), "<PARAM oi_reclutado=\""+Ctrl("oi_reclutado").GetXValue()+"\" />"); 		
  if (puesto.oi_puesto!="0")  
  {
  	Ctrl("oi_empresa").SetXValue(puesto.oi_empresa);
  	Ctrl("oi_puesto").SetXValue(puesto.oi_puesto);
  } 
  else 
  {
  	Ctrl("oi_puesto").SetXValue("");
  }

}

qry:select.qry:xquery:
for $r in sql(' SELECT SDP01_CV.c_sexo FROM SDP14_RECLUTADOS, SDP01_CV JOIN SDP14_RECLUTADOS.oi_cv INNER SDP01_CV.oi_cv
WHERE SDP14_RECLUTADOS.oi_reclutado = {#FILTRO:@oi_reclutado}
')/ROWS/ROW
